import { Router } from "express";
import { authRouter } from "./auth.routes.js";
import { dashboardRouter } from "./dashboard.routes.js";
import { driversRouter } from "./drivers.routes.js";
import { healthRouter } from "./health.routes.js";
import { localsRouter } from "./locals.routes.js";
import { productsRouter } from "./products.routes.js";
import { receptionistsRouter } from "./receptionists.routes.js";
import { geocodeRouter } from "./geocode.routes.js";
import { ordersRouter } from "./orders.routes.js";
export const apiRouter = Router();
apiRouter.use("/health", healthRouter);
apiRouter.use("/auth", authRouter);
apiRouter.use("/dashboard", dashboardRouter);
apiRouter.use("/locals", localsRouter);
apiRouter.use("/products", productsRouter);
apiRouter.use("/receptionists", receptionistsRouter);
apiRouter.use("/drivers", driversRouter);
apiRouter.use("/geocode", geocodeRouter);
apiRouter.use("/orders", ordersRouter);
